574	/* =============================================================
575	   SESSION LIST — adapted from `design_handoff_tide/Tide Sessions.html`.
576	   The design's row class names were `.session-item` / `.session-agent-dot`
577	   / `.session-title` / `.session-more`; we use the `.session-row*`
578	   namespace so all row rules sit under one obvious family and don't
579	   collide with the older `.session-item` ports if any leak through.
580	   The 34px row height is **load-bearing** for Task 14's inline
581	   delete-confirm — the confirm UI swaps row contents in place at the
582	   same height, so the list doesn't reflow on confirm/cancel.
583	   ============================================================= */
584	
585	.sessions-group-label {
586	  font-size: 10px;
587	  letter-spacing: 0.12em;
588	  text-transform: uppercase;
589	  color: var(--ink-ghost);
590	  padding: 8px 12px 4px;
591	  font-weight: 500;
592	}
593	
594	.session-row {
595	  all: unset;
596	  cursor: pointer;
597	  display: flex;
598	  flex-direction: row;
599	  align-items: flex-start;
600	  gap: 8px;
601	  padding: 8px 12px;
602	  border-radius: 4px;
603	  color: var(--ink-soft);
604	  transition: background 120ms ease, color 120ms ease;
605	  position: relative;
606	  box-sizing: border-box;
607	  height: 34px;
608	  width: 100%;
609	}
610	.session-row:hover {
611	  background: var(--bg-deep);
612	  color: var(--ink);
613	}
614	.session-row.active {
615	  background: var(--bg-deep);
616	  color: var(--ink);
617	}
618	.session-row.active::before {
619	  content: '';
620	  position: absolute;
621	  left: 0;
622	  top: 10px;
623	  bottom: 10px;
624	  width: 2px;
625	  background: var(--accent);
626	  border-radius: 2px;
627	}
628	.session-row-dot {
629	  width: 6px;
630	  height: 6px;
631	  border-radius: 50%;
632	  margin-top: 7px;
633	  flex-shrink: 0;
