635	}
636	.session-row:hover .session-row-dot,
637	.session-row.active .session-row-dot { opacity: 1; }
638	.session-row-title {
639	  font-size: 13px;
640	  line-height: 1.35;
641	  letter-spacing: -0.005em;
642	  white-space: nowrap;
643	  overflow: hidden;
644	  text-overflow: ellipsis;
645	  flex: 1;
646	  min-width: 0;
647	}
