862	/* =============================================================
863	   COMPOSER — fixed to the bottom of the chat pane (not over the
864	   sidebar). Adapted from `design_handoff_tide/Tide Sessions.html`.
865	   The 28px attach button + 30px send circle + 28px textarea
866	   min-height are load-bearing: at the field's `align-items:
867	   flex-end`, equal heights mean the bottoms align AND the
868	   optical centers align on the first line. Don't drop the
869	   28px floor on the textarea — the natural 22px wrecks this.
870	   ============================================================= */
871	
872	.composer {
873	  position: fixed;
874	  bottom: 0;
875	  left: 240px;
876	  right: 0;
877	  transition: left 220ms cubic-bezier(.2,.7,.2,1);
878	  padding: 40px 24px 22px;
879	  background: linear-gradient(
880	    to top,
881	    var(--bg) 60%,
882	    color-mix(in srgb, var(--bg) 80%, transparent) 85%,
883	    transparent 100%
884	  );
885	  display: flex;
886	  justify-content: center;
887	  z-index: 20;
888	}
889	body.sidebar-collapsed .composer { left: 56px; }
890	
891	.composer-inner {
892	  width: 100%;
893	  max-width: 640px;
894	  /* Per Tide spec the inner wrap also handles top/bottom rhythm
895	     for the field; the outer .composer carries the fade-out. */
896	  margin: 0 auto;
897	  padding: 12px 24px 16px;
898	}
899	
900	.composer-field {
901	  position: relative;
902	  display: flex;
903	  align-items: flex-end;
904	  gap: 10px;
905	  background: var(--surface-raised);
906	  border: 1px solid var(--rule);
907	  border-radius: 8px;
908	  padding: 10px 12px 10px 14px;
909	  box-shadow: var(--shadow-sm);
910	  transition: border-color 140ms ease, box-shadow 140ms ease;
911	}
912	.composer-field:focus-within {
913	  border-color: color-mix(in srgb, var(--accent) 40%, var(--rule));
914	  box-shadow: 0 0 0 4px color-mix(in srgb, var(--accent) 14%, transparent),
915	    var(--shadow-sm);
916	}
917	
918	.composer-input {
919	  flex: 1 1 auto;
920	  min-width: 0;
921	  resize: none;
922	  border: 0;
923	  outline: 0;
924	  background: transparent;
925	  color: var(--ink);
926	  font-family: var(--sans);
927	  font-size: 15px;
928	  line-height: 1.55;
929	  /* 28px floor matches attach-btn (28px) and send-btn (30px) when
930	     align-items: flex-end so the first line bottom-aligns and
931	     optically centers. */
932	  min-height: 28px;
933	  max-height: 200px;
934	  padding: 2px 0;
935	  box-sizing: border-box;
936	}
937	.composer-input::placeholder { color: var(--ink-mute); }
938	
939	.attach-btn {
940	  all: unset;
941	  cursor: pointer;
942	  width: 28px;
943	  height: 28px;
944	  border-radius: 50%;
945	  color: var(--ink-mute);
946	  display: flex;
947	  align-items: center;
948	  justify-content: center;
949	  flex-shrink: 0;
950	  margin-right: 4px;
951	  transition: background 120ms ease, color 120ms ease;
952	  font-size: 16px;
953	  line-height: 1;
954	}
955	.attach-btn:hover:not([disabled]) {
956	  background: var(--bg-deep);
957	  color: var(--ink);
958	}
959	.attach-btn[aria-expanded="true"] {
960	  background: var(--bg-deep);
961	  color: var(--ink);
962	}
963	.attach-btn[disabled] {
964	  cursor: default;
965	  opacity: 0.6;
966	}
967	
968	.send-btn {
969	  all: unset;
970	  cursor: pointer;
971	  width: 30px;
972	  height: 30px;
973	  border-radius: 50%;
974	  background: var(--ink-ghost);
975	  color: var(--bg);
976	  display: flex;
977	  align-items: center;
978	  justify-content: center;
979	  flex-shrink: 0;
980	  transition: background 140ms ease, transform 140ms ease, filter 140ms ease;
981	}
982	/* When the textarea has any content, light up the send circle. We use
983	   `:has()` against the placeholder-shown state so this is a pure-CSS
984	   ready toggle — no JS observer needed. */
985	.composer-field:has(.composer-input:not(:placeholder-shown)) .send-btn,
986	.send-btn.ready {
987	  background: var(--accent);
988	}
989	.composer-field:has(.composer-input:not(:placeholder-shown)) .send-btn:hover,
990	.send-btn.ready:hover {
991	  transform: scale(1.05);
992	  filter: brightness(1.05);
993	}
994	
995	.composer-hint {
996	  margin-top: 8px;
997	  font-size: 10.5px;
998	  color: var(--ink-ghost);
999	  text-align: center;
1000	  letter-spacing: 0.04em;
1001	  opacity: 0;
1002	  transition: opacity 140ms ease;
1003	  pointer-events: none;
1004	}
1005	.composer:hover .composer-hint,
1006	.composer:focus-within .composer-hint {
1007	  opacity: 1;
1008	}
1009	.composer-hint kbd {
1010	  font-family: var(--mono);
1011	  font-size: 10px;
1012	  color: var(--ink-mute);
1013	}
