1089	/* =============================================================
1090	   THREAD + TIMELINE — adapted from `design_handoff_tide/Tide
1091	   Sessions.html` (`.timeline`, `.msg`, `.msg-body`, `.msg-actions`,
1092	   `.intro`). Tide uses no avatars and no meta column — role is
1093	   conveyed by alignment + a subtle wash on the user side. Bottom
1094	   padding (220px) is load-bearing: it clears the fixed-bottom
1095	   composer so the last message is fully visible above it.
1096	   ============================================================= */
1097	
1098	.thread-root {
1099	  display: flex;
1100	  flex-direction: column;
1101	  flex: 1;
1102	  min-height: 0;
1103	}
