1133	}
1134	
1135	/* ---- Message: no avatar, no meta column. Just text. ---- */
1136	.msg {
1137	  margin-bottom: 22px;
1138	  position: relative;
1139	  max-width: 100%;
1140	}
1141	
1142	.msg-body {
1143	  font-family: var(--sans);
1144	  font-size: 15px;
1145	  line-height: 1.6;
1146	  color: var(--ink);
1147	  white-space: pre-wrap;
1148	  overflow-wrap: break-word;
1149	}
1150	.msg-body p { margin-bottom: 0.6em; }
1151	.msg-body p:last-child { margin-bottom: 0; }
1152	
1153	/* User: right-aligned with a warm wash. The wash is `--you-wash`
1154	   (a barely-visible warm tint) — not a bubble in the chat-app sense,
1155	   more like a highlighted run of text. */
1156	.msg.you {
1157	  display: flex;
1158	  flex-direction: column;
1159	  align-items: flex-end;
1160	}
1161	.msg.you .msg-body {
1162	  background: var(--you-wash);
1163	  color: var(--you-ink);
1164	  padding: 7px 12px;
1165	  border-radius: 6px;
1166	  max-width: 78%;
1167	}
1168	.msg.you .msg-actions {
1169	  justify-content: flex-end;
1170	}
1171	
1172	/* Agent: serif (well, the channel-web token aliases `--serif` to
1173	   `--sans` for now), inline prose, capped at ~56ch for readability. */
1174	.msg.agent .msg-body {
1175	  font-family: var(--serif);
1176	  font-size: 15px;
1177	  line-height: 1.55;
1178	  letter-spacing: -0.008em;
1179	  max-width: 56ch;
1180	}
1181	
1182	/* Action bar — autohides until message hover or focus. Keep button
1183	   sizes small + monochrome; the actions are quiet by design. */
1184	.msg-actions {
1185	  display: flex;
1186	  gap: 8px;
1187	  align-items: center;
1188	  margin-top: 4px;
1189	  font-size: 11px;
1190	  color: var(--ink-ghost);
1191	  opacity: 0;
1192	  transition: opacity 140ms ease;
1193	  letter-spacing: 0.02em;
1194	  white-space: nowrap;
1195	  font-family: var(--mono);
1196	}
1197	.msg:hover .msg-actions,
1198	.msg-actions:focus-within { opacity: 1; }
1199	.msg-action {
1200	  all: unset;
1201	  cursor: pointer;
