1686	    z-index: 50;
1687	    box-shadow: 0 0 40px rgba(0, 0, 0, 0.08);
1688	  }
1689	  body.sidebar-open .sidebar { transform: translateX(0); }
1690	  /* Desktop collapse is irrelevant on mobile — keep the rail at full
1691	     slide-over width and rely on `sidebar-open` to show/hide. */
1692	  body.sidebar-collapsed .sidebar { transform: translateX(-100%); }
1693	  body.sidebar-open.sidebar-collapsed .sidebar { transform: translateX(0); }
