1	/**
2	 * App — auth-gated root component.
3	 *
4	 * Boot flow:
5	 *   1. `loading` — fetch `/api/auth/get-session` on mount.
6	 *   2. `unauthenticated` — render `<LoginPage />` (single Google CTA).
7	 *   3. `authenticated` — render `<AppContent />` with the assistant-ui
8	 *      runtime, sidebar, session header, and thread.
9	 *
10	 * Global keyboard shortcuts (⌘\, ⌘N) live inside `<AppContent>` so they
11	 * only bind once the user is signed in. Unauthenticated state can't
12	 * accidentally trigger a session create against an unknown user.
13	 *
14	 * Per-test-file note: components in `components/` render in isolation and
15	 * bypass the auth gate. Only `App.tsx` is gated; downstream tests don't
16	 * need to mock `/api/auth/*`.
17	 */
18	import { useEffect, useState } from 'react';
19	import { AssistantRuntimeProvider } from '@assistant-ui/react';
20	import { useAxChatRuntime } from './lib/runtime';
21	import { getSession, type AuthUser } from './lib/auth';
22	import {
23	  hydrateSidebarCollapsed,
24	  setSidebarCollapsed,
25	  setSidebarOpen,
26	  useSidebarOpen,
27	} from './lib/sidebar-collapse';
28	import { hydrateTheme } from './lib/theme';
29	import { useAgentStore } from './lib/agent-store';
30	import { sessionStoreActions } from './lib/session-store';
31	import { LoginPage } from './components/LoginPage';
32	import { Sidebar } from './components/Sidebar';
33	import { SessionHeader } from './components/SessionHeader';
34	import { Thread } from './components/Thread';
35	import { AdminPanel } from './components/admin/AdminPanel';
36	import { UserProvider } from './lib/user-context';
37	import type { AdminView } from './lib/admin';
38	
39	type AuthState = 'loading' | 'authenticated' | 'unauthenticated';
40	
41	export const App = () => {
42	  const [authState, setAuthState] = useState<AuthState>('loading');
43	  const [user, setUser] = useState<AuthUser | null>(null);
44	
45	  useEffect(() => {
46	    let cancelled = false;
47	    void (async () => {
48	      try {
49	        const session = await getSession();
50	        if (cancelled) return;
51	        if (session?.user) {
52	          setUser(session.user);
53	          setAuthState('authenticated');
54	        } else {
55	          setAuthState('unauthenticated');
56	        }
57	      } catch {
58	        // Network/DNS/offline — treat as unauthenticated so the user
59	        // sees the sign-in CTA instead of "connecting…" forever.
60	        if (!cancelled) setAuthState('unauthenticated');
61	      }
62	    })();
63	    return () => {
64	      cancelled = true;
65	    };
66	  }, []);
67	
68	  if (authState === 'loading') {
69	    return <div className="app-loading">connecting…</div>;
70	  }
71	  if (authState === 'unauthenticated') {
72	    return <LoginPage />;
73	  }
74	  return <AppContent user={user!} />;
75	};
76	
77	const AppContent = ({ user }: { user: AuthUser }) => {
78	  const { agents, selectedAgentId, pendingAgentId } = useAgentStore();
79	  const runtime = useAxChatRuntime(undefined, undefined, user.id, undefined);
80	  // `adminView` is set by the user menu's Admin entries. AdminPanel
81	  // renders below when non-null.
82	  const [adminView, setAdminView] = useState<AdminView>(null);
83	  // Mobile slide-over open state (Task 27). Used to render the scrim
84	  // that closes the sidebar on tap. Desktop CSS hides the scrim.
85	  const sidebarOpen = useSidebarOpen();
86	
87	  useEffect(() => {
88	    // Apply persisted sidebar + theme state before first paint of any subscriber.
89	    hydrateSidebarCollapsed();
90	    hydrateTheme();
91	
92	    // Global keyboard shortcuts:
93	    //  - ⌘\ (or Ctrl+\) toggles the sidebar. (Ctrl+\ has no browser
94	    //    conflict so we honor it cross-platform.)
95	    //  - ⌘N creates a new session for the active agent. We deliberately
